#include <iostream>
#include <string>
#include <type_traits>
#include <variant>

int main() {
    char tag{};
    if (!(std::cin >> tag)) return 1;
    std::variant<int, std::string> value;
    if (tag == 'i') { int number{}; if (!(std::cin >> number)) return 1; value = number; }
    else if (tag == 's') { std::string text; if (!(std::cin >> text)) return 1; value = text; }
    else { std::cout << "invalid\n"; return 0; }
    std::visit([](const auto& item) { using T = std::decay_t<decltype(item)>; if constexpr (std::is_same_v<T, int>) std::cout << "int:" << item << '\n'; else std::cout << "text:" << item << '\n'; }, value);
}
